import { useLocation, useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import api from "../../api/axios";

const formatDisplayTime = (time) => {
  if (!time) return "Select a session";
  const [hours, minutes] = time.split(":").map(Number);
  const suffix = hours >= 12 ? "PM" : "AM";
  const hour12 = hours % 12 || 12;
  return `${hour12}:${String(minutes).padStart(2, "0")} ${suffix}`;
};

export default function CustomerBookAppointment() {
  const { state } = useLocation();
  const navigate = useNavigate();
  const [vehicleId, setVehicleId] = useState("");
  const [vehicles, setVehicles] = useState([]);
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");
  const [availableSlots, setAvailableSlots] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [minDate, setMinDate] = useState("");

  useEffect(() => {
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    setMinDate(tomorrow.toISOString().split("T")[0]);
  }, []);

  useEffect(() => {
    const loadVehicles = async () => {
      try {
        const res = await api.get("/vehicles");
        const available = res.data.filter((vehicle) => vehicle.status === "available");
        setVehicles(available);

        if (state?.vehicleId) {
          setVehicleId(state.vehicleId);
        } else if (available.length > 0) {
          setVehicleId(available[0]._id);
        }
      } catch (err) {
        alert(err.response?.data?.message || "Failed to load vehicles");
      }
    };

    loadVehicles();
  }, [state]);

  useEffect(() => {
    const loadTimeSlots = async () => {
      if (!date) {
        setAvailableSlots([]);
        setTime("");
        return;
      }

      setLoading(true);
      setError("");
      setTime("");

      try {
        const res = await api.get(`/customer/appointments/available-slots/${date}`);
        const slots = res.data.slots || [];
        if (slots.length === 0) {
          setError("No available slots on this date. Please select another date.");
          setAvailableSlots([]);
        } else {
          setAvailableSlots(slots);
        }
      } catch (err) {
        const errorMsg = err.response?.data?.message || err.response?.data?.errors?.[0] || "Failed to load available slots";
        setError(errorMsg);
        setAvailableSlots([]);
      } finally {
        setLoading(false);
      }
    };

    loadTimeSlots();
  }, [date]);

  const submit = async (e) => {
    e.preventDefault();
    if (!vehicleId) return alert("Please select a vehicle");
    if (!date) return alert("Please select a date");
    if (!time) return alert("Please select a time");

    try {
      await api.post("/customer/appointments/book", { vehicle: vehicleId, date, time });
      navigate("/my-appointments");
    } catch (err) {
      alert(err.response?.data?.message || "Booking failed");
    }
  };

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Book Appointment</div>
          <div className="pageSub">Choose a vehicle, date, and one available hourly session between 9:00 AM and 5:00 PM.</div>
        </div>
      </div>

      <div className="card cardPad" style={{ maxWidth: "760px", margin: "0 auto" }}>
        <div style={{ display: "grid", gap: "10px", marginBottom: "24px" }}>
          <div style={{ fontSize: "12px", textTransform: "uppercase", letterSpacing: "0.12em", color: "var(--primary)", fontWeight: 700 }}>
            Customer Booking
          </div>
          <div style={{ fontSize: "28px", fontWeight: 800, color: "var(--navy)" }}>Reserve your visit</div>
          <div style={{ color: "var(--text-muted)", lineHeight: 1.6 }}>
            A simple premium booking flow for showroom visits and test drives.
          </div>
        </div>

        <form onSubmit={submit} style={{ display: "grid", gap: "22px" }}>
          <div style={{ display: "grid", gap: "18px" }}>
            <div>
              <label className="label">Vehicle</label>
              <select value={vehicleId} onChange={(e) => setVehicleId(e.target.value)} className="select" required>
                {vehicles.length === 0 ? (
                  <option value="">No available vehicles</option>
                ) : (
                  vehicles.map((vehicle) => (
                    <option key={vehicle._id} value={vehicle._id}>
                      {vehicle.brand} {vehicle.model || vehicle.type || ""} ({vehicle.year})
                    </option>
                  ))
                )}
              </select>
            </div>

            <div>
              <label className="label">Appointment Date</label>
              <input type="date" required value={date} onChange={(e) => setDate(e.target.value)} min={minDate} className="input" />
              <div style={{ fontSize: "12px", color: "var(--text-muted)", marginTop: "6px" }}>
                Select a future date. Holidays and closure events are automatically blocked.
              </div>
            </div>

            {error ? (
              <div
                style={{
                  padding: "14px 16px",
                  borderRadius: "16px",
                  border: "1px solid rgba(186, 94, 94, 0.18)",
                  background: "rgba(255,255,255,0.92)",
                  color: "var(--danger)",
                  fontWeight: 600,
                }}
              >
                {error}
              </div>
            ) : null}

            <div>
              <label className="label">Available Sessions</label>
              {loading ? (
                <div className="card cardPad" style={{ color: "var(--text-muted)" }}>
                  Loading available sessions...
                </div>
              ) : date ? (
                availableSlots.length > 0 ? (
                  <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(140px, 1fr))", gap: "10px", marginTop: "8px" }}>
                    {availableSlots.map((slot) => {
                      const selected = time === slot.time;
                      const disabled = slot.availableStaffCount === 0;
                      return (
                        <button
                          key={slot.time}
                          type="button"
                          onClick={() => !disabled && setTime(slot.time)}
                          className="btn"
                          disabled={disabled}
                          style={{
                            padding: "12px 10px",
                            borderRadius: "16px",
                            background: selected ? "linear-gradient(135deg, #0C3A57 0%, #15517a 58%, #8DBB01 100%)" : "rgba(255,255,255,0.92)",
                            color: selected ? "#fff" : "var(--navy)",
                            border: selected ? "1px solid transparent" : "1px solid var(--border)",
                            opacity: disabled ? 0.45 : 1,
                            cursor: disabled ? "not-allowed" : "pointer",
                          }}
                          title={`${slot.availableStaffCount} staff member${slot.availableStaffCount !== 1 ? "s" : ""} available`}
                        >
                          <div style={{ fontWeight: 700 }}>{formatDisplayTime(slot.time)}</div>
                          <div style={{ fontSize: "12px", marginTop: "4px" }}>{slot.availableStaffCount} available</div>
                        </button>
                      );
                    })}
                  </div>
                ) : null
              ) : (
                <div className="card cardPad" style={{ color: "var(--text-muted)" }}>
                  Select a date to see available sessions.
                </div>
              )}
            </div>
          </div>

          <div
            style={{
              padding: "16px",
              borderRadius: "18px",
              border: "1px solid var(--border)",
              background: "rgba(236, 236, 236, 0.42)",
              color: "var(--text-secondary)",
              lineHeight: 1.65,
            }}
          >
            Selected session: <strong style={{ color: "var(--navy)" }}>{formatDisplayTime(time)}</strong>
          </div>

          <div style={{ display: "flex", gap: "12px" }}>
            <button type="button" onClick={() => navigate("/")} className="btn" style={{ flex: 1 }}>
              Cancel
            </button>
            <button type="submit" disabled={vehicles.length === 0 || !date || !time} className="btn btnPrimary" style={{ flex: 1 }}>
              Book Appointment
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
